function a(r){if(r==null||r==="")return[];if(Array.isArray(r))return r.map(String).flatMap(t=>t.split(/[,，]/)).map(t=>t.trim()).filter(Boolean);if(typeof r=="string"){let t=r.trim();if(!t)return[];try{let i=JSON.parse(t);if(Array.isArray(i))return i.map(String).map(e=>e.trim()).filter(Boolean);if(typeof i=="string"){try{const e=JSON.parse(i);if(Array.isArray(e))return e.map(String).map(n=>n.trim()).filter(Boolean)}catch{}return i.split(/[,，]/).map(e=>e.trim()).filter(Boolean)}}catch{}return t.split(/[,，]/).map(i=>i.trim()).filter(Boolean)}return[]}function p(r){const t=Array.isArray(r)?r:a(r);return JSON.stringify(t.map(String).map(i=>i.trim()).filter(Boolean))}export{p as c,a as p};
